import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum UserRole {
  STUDENT = 'STUDENT',
  PARENT = 'PARENT',
  ADMIN = 'ADMIN'
}

export interface BusStop {
  id: string;
  name: string;
  time: string;
  status: 'passed' | 'upcoming' | 'current';
}

export interface BusRoute {
  id: string;
  name: string;
  driver: string;
  driverPhone: string;
  numberPlate: string;
  eta: string; // Estimated time to user's stop
  stops: BusStop[];
}

export interface ChatMessage {
  id: string;
  sender: 'user' | 'bot';
  text: string;
  timestamp: Date;
}

export type ViewState = 'TRACKING' | 'CHAT' | 'SCAN' | 'ADMIN' | 'PROFILE';

import { GoogleGenAI } from "@google/genai";

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

const SYSTEM_INSTRUCTION_CHAT = `You are the intelligent assistant for the "CollegeBus Tracker" app. 
Your goal is to help students, parents, and admins with transport-related queries.
You can answer questions about bus schedules (assume standard 8 AM - 4 PM college timing), safety protocols, and general college transport FAQs.
Keep answers concise, friendly, and helpful. Tone should be professional yet accessible, similar to a helpful support agent.`;

const SYSTEM_INSTRUCTION_IMAGE = `You are an visual assistant for the "CollegeBus Tracker" app.
Analyze the image provided. 
If it looks like a lost item, describe it in detail so it can be logged in the "Lost & Found" system.
If it looks like a printed bus schedule or notice, extract the key dates and times.
If it looks like a vehicle or maintenance issue, describe the damage or condition.
Keep the response structured and actionable.`;

export const sendChatMessage = async (message: string, history: string[]): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: [
        ...history.map(h => ({ role: 'user', parts: [{ text: h }] })), // Simplified history for this demo
        { role: 'user', parts: [{ text: message }] }
      ],
      config: {
        systemInstruction: SYSTEM_INSTRUCTION_CHAT,
      }
    });
    return response.text || "I couldn't generate a response.";
  } catch (error) {
    console.error("Gemini Chat Error:", error);
    return "Sorry, I'm having trouble connecting to the transport network right now. Please try again.";
  }
};

export const analyzeImage = async (base64Image: string, prompt: string): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: 'image/jpeg', // Assuming jpeg for simplicity, or detect from input
              data: base64Image
            }
          },
          { text: prompt || "Analyze this image for the college transport system." }
        ]
      },
      config: {
        systemInstruction: SYSTEM_INSTRUCTION_IMAGE
      }
    });
    return response.text || "Analysis complete, but no description generated.";
  } catch (error) {
    console.error("Gemini Image Error:", error);
    return "Failed to analyze the image. Please ensure it's a clear photo.";
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { Send, Bot, User, Loader2 } from 'lucide-react';
import { ChatMessage } from '../types';
import { sendChatMessage } from '../services/geminiService';
import { BotIcon } from './BotIcon';

const AIChatbot: React.FC = () => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      id: 'welcome',
      sender: 'bot',
      text: 'Hi! I am your CollegeBus Assistant. Ask me about schedules, routes, or lost items!',
      timestamp: new Date()
    }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim()) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      sender: 'user',
      text: input,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      const history = messages.map(m => m.text);
      const responseText = await sendChatMessage(userMsg.text, history);

      const botMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        sender: 'bot',
        text: responseText,
        timestamp: new Date()
      };
      setMessages(prev => [...prev, botMsg]);
    } catch (error) {
       console.error(error);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-full bg-slate-50 pb-20">
      <div className="bg-white p-4 shadow-sm z-10 sticky top-0">
        <h2 className="text-lg font-bold text-slate-800 flex items-center gap-2">
          <BotIcon className="w-6 h-6 text-yellow-500" />
          Bus Assistant
        </h2>
        <p className="text-xs text-slate-500">Powered by Gemini 3 Pro</p>
      </div>

      <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 space-y-4">
        {messages.map((msg) => (
          <div
            key={msg.id}
            className={`flex ${msg.sender === 'user' ? 'justify-end' : 'justify-start'}`}
          >
            <div
              className={`max-w-[80%] p-4 rounded-2xl shadow-sm text-sm leading-relaxed ${
                msg.sender === 'user'
                  ? 'bg-slate-900 text-white rounded-br-none'
                  : 'bg-white text-slate-700 rounded-bl-none border border-slate-100'
              }`}
            >
              {msg.text}
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start">
            <div className="bg-white p-4 rounded-2xl rounded-bl-none shadow-sm border border-slate-100">
              <Loader2 className="w-5 h-5 animate-spin text-yellow-500" />
            </div>
          </div>
        )}
      </div>

      <div className="p-4 bg-white border-t border-slate-100 sticky bottom-[80px]">
        <div className="flex items-center gap-2 bg-slate-100 rounded-full px-4 py-2 border border-slate-200">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder="Ask about bus 101..."
            className="flex-1 bg-transparent outline-none text-slate-800 text-sm placeholder:text-slate-400"
          />
          <button
            onClick={handleSend}
            disabled={isLoading || !input.trim()}
            className="bg-yellow-400 p-2 rounded-full text-slate-900 hover:bg-yellow-500 disabled:opacity-50 transition-colors"
          >
            <Send className="w-4 h-4" />
          </button>
        </div>
      </div>
    </div>
  );
};

export default AIChatbot;

import React, { useState } from 'react';
import { Camera, Upload, X, Loader2, Sparkles, AlertCircle } from 'lucide-react';
import { analyzeImage } from '../services/geminiService';

const ImageAnalyzer: React.FC = () => {
  const [image, setImage] = useState<string | null>(null);
  const [result, setResult] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [prompt, setPrompt] = useState('');

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setImage(reader.result as string);
        setResult(null);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleAnalyze = async () => {
    if (!image) return;
    setLoading(true);
    setResult(null);

    try {
      // Remove data URL prefix for Gemini API
      const base64Data = image.split(',')[1];
      const analysis = await analyzeImage(base64Data, prompt);
      setResult(analysis);
    } catch (error) {
      console.error(error);
      setResult("Failed to analyze image. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-full bg-slate-50 p-6 pb-24 overflow-y-auto">
      <div className="mb-6">
        <h2 className="text-2xl font-bold text-slate-900">Scan & Check</h2>
        <p className="text-slate-500 text-sm">Upload photos of lost items, notices, or bus issues.</p>
      </div>

      <div className="flex-1 flex flex-col items-center">
        {!image ? (
          <label className="w-full aspect-[4/3] rounded-3xl border-2 border-dashed border-slate-300 bg-white flex flex-col items-center justify-center cursor-pointer hover:border-yellow-400 hover:bg-yellow-50 transition-all group shadow-sm">
             <div className="bg-slate-100 p-4 rounded-full mb-4 group-hover:bg-yellow-200 transition-colors">
                <Camera className="w-8 h-8 text-slate-400 group-hover:text-yellow-700" />
             </div>
             <span className="font-semibold text-slate-600 group-hover:text-yellow-800">Tap to Take Photo</span>
             <span className="text-xs text-slate-400 mt-1">or upload from gallery</span>
             <input type="file" accept="image/*" className="hidden" onChange={handleFileChange} />
          </label>
        ) : (
          <div className="w-full space-y-4">
            <div className="relative w-full aspect-[4/3] rounded-3xl overflow-hidden shadow-lg">
              <img src={image} alt="Preview" className="w-full h-full object-cover" />
              <button 
                onClick={() => setImage(null)}
                className="absolute top-3 right-3 bg-black/50 text-white p-2 rounded-full backdrop-blur-md hover:bg-black/70"
              >
                <X className="w-4 h-4" />
              </button>
            </div>

            <div className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100">
                <label className="text-xs font-bold text-slate-500 uppercase tracking-wide mb-2 block">Optional Prompt</label>
                <input 
                    type="text" 
                    value={prompt}
                    onChange={(e) => setPrompt(e.target.value)}
                    placeholder="e.g. Is this a math textbook?"
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 text-sm focus:outline-none focus:border-yellow-400"
                />
            </div>

            <button
              onClick={handleAnalyze}
              disabled={loading}
              className="w-full bg-slate-900 text-white font-bold py-4 rounded-xl flex items-center justify-center gap-2 hover:bg-slate-800 disabled:opacity-50 shadow-xl shadow-slate-200"
            >
              {loading ? <Loader2 className="w-5 h-5 animate-spin" /> : <Sparkles className="w-5 h-5 text-yellow-400" />}
              {loading ? 'Analyzing with Gemini...' : 'Analyze Image'}
            </button>
          </div>
        )}

        {result && (
          <div className="mt-6 w-full bg-white p-6 rounded-2xl shadow-md border-l-4 border-yellow-400 animate-in fade-in slide-in-from-bottom-4">
            <h3 className="font-bold text-slate-900 mb-2 flex items-center gap-2">
                <Sparkles className="w-4 h-4 text-yellow-500" /> 
                AI Analysis
            </h3>
            <p className="text-slate-600 text-sm leading-relaxed whitespace-pre-wrap">{result}</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default ImageAnalyzer;

import React from 'react';
import { Map, MessageSquare, Scan, User, LayoutDashboard } from 'lucide-react';
import { ViewState } from '../types';

interface BottomNavProps {
  currentView: ViewState;
  setView: (view: ViewState) => void;
  userRole: 'student' | 'admin';
}

const BottomNav: React.FC<BottomNavProps> = ({ currentView, setView, userRole }) => {
  const NavItem = ({ view, icon: Icon, label }: { view: ViewState; icon: any; label: string }) => (
    <button
      onClick={() => setView(view)}
      className={`flex flex-col items-center justify-center w-full h-full space-y-1 ${
        currentView === view ? 'text-slate-900' : 'text-slate-400 hover:text-slate-600'
      }`}
    >
      <div className={`p-1.5 rounded-xl transition-all ${currentView === view ? 'bg-yellow-400 shadow-md transform -translate-y-2' : ''}`}>
        <Icon className={`w-6 h-6 ${currentView === view ? 'text-black' : 'currentColor'}`} strokeWidth={currentView === view ? 2.5 : 2} />
      </div>
      <span className={`text-[10px] font-medium transition-opacity ${currentView === view ? 'opacity-100 font-bold' : 'opacity-70'}`}>
        {label}
      </span>
    </button>
  );

  return (
    <div className="fixed bottom-0 left-0 right-0 h-20 bg-white border-t border-slate-200 flex justify-around items-center px-2 pb-2 z-50 rounded-t-3xl shadow-[0_-5px_15px_rgba(0,0,0,0.05)]">
      <NavItem view="TRACKING" icon={Map} label="Track" />
      <NavItem view="CHAT" icon={MessageSquare} label="Help" />
      <NavItem view="SCAN" icon={Scan} label="Scan" />
      {userRole === 'admin' ? (
        <NavItem view="ADMIN" icon={LayoutDashboard} label="Admin" />
      ) : (
        <NavItem view="PROFILE" icon={User} label="Profile" />
      )}
    </div>
  );
};

export default BottomNav;

import React, { useState } from 'react';
import { ViewState } from './types';
import MapInterface from './components/MapInterface';
import AIChatbot from './components/AIChatbot';
import ImageAnalyzer from './components/ImageAnalyzer';
import BottomNav from './components/BottomNav';
import AdminDashboard from './components/AdminDashboard';
import { User } from 'lucide-react';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewState>('TRACKING');
  // Simple mock login state toggler for demo
  const [userRole, setUserRole] = useState<'student' | 'admin'>('student');

  const renderView = () => {
    switch (currentView) {
      case 'TRACKING':
        return <MapInterface />;
      case 'CHAT':
        return <AIChatbot />;
      case 'SCAN':
        return <ImageAnalyzer />;
      case 'ADMIN':
        return <AdminDashboard />;
      case 'PROFILE':
        return (
           <div className="flex flex-col items-center justify-center h-full bg-slate-50 p-6">
              <div className="w-24 h-24 bg-yellow-400 rounded-full flex items-center justify-center mb-6 shadow-xl border-4 border-white">
                 <User className="w-10 h-10 text-slate-900" />
              </div>
              <h2 className="text-2xl font-bold text-slate-900">Alex Student</h2>
              <p className="text-slate-500 mb-8">Computer Science • Year 2</p>

              <div className="w-full max-w-xs space-y-3">
                 <button className="w-full bg-white border border-slate-200 p-4 rounded-xl flex justify-between items-center shadow-sm hover:bg-slate-50">
                    <span className="font-semibold text-slate-700">My Route</span>
                    <span className="text-yellow-600 font-bold">#101</span>
                 </button>
                 <button className="w-full bg-white border border-slate-200 p-4 rounded-xl flex justify-between items-center shadow-sm hover:bg-slate-50">
                    <span className="font-semibold text-slate-700">Semester Pass</span>
                    <span className="text-green-600 font-bold">Active</span>
                 </button>

                 <div className="pt-8 border-t border-slate-200 mt-8">
                    <p className="text-xs text-center text-slate-400 mb-2">Demo Control</p>
                    <button 
                        onClick={() => {
                            const newRole = userRole === 'student' ? 'admin' : 'student';
                            setUserRole(newRole);
                            if(newRole === 'admin') setCurrentView('ADMIN');
                            else setCurrentView('TRACKING');
                        }}
                        className="w-full bg-slate-800 text-white py-3 rounded-xl font-bold text-sm"
                    >
                        Switch to {userRole === 'student' ? 'Admin' : 'Student'} View
                    </button>
                 </div>
              </div>
           </div>
        );
      default:
        return <MapInterface />;
    }
  };

  return (
    <div className="h-screen w-screen flex flex-col bg-slate-50 overflow-hidden">
        {/* Main Content Area */}
        <main className="flex-1 relative overflow-hidden">
            {renderView()}
        </main>

        {/* Navigation */}
        <BottomNav currentView={currentView} setView={setCurrentView} userRole={userRole} />
    </div>
  );
};

export default App;
